-- MVP 1 Society Builder foundation only. No treasury, ledger, federation, property, youth, or business engines.
CREATE TABLE IF NOT EXISTS societies (id INTEGER PRIMARY KEY, slug VARCHAR(128) NOT NULL UNIQUE, name VARCHAR(255) NOT NULL, type VARCHAR(128) NOT NULL DEFAULT 'Custom', description TEXT NOT NULL DEFAULT '', community_served TEXT NOT NULL DEFAULT '', location VARCHAR(255) NOT NULL DEFAULT '', first_focus VARCHAR(128) NOT NULL DEFAULT '', visibility VARCHAR(128) NOT NULL DEFAULT 'Private', lifecycle_stage VARCHAR(128) NOT NULL DEFAULT 'Exploring', founder_user_id INTEGER, parent_society_id INTEGER, root_society_id INTEGER, is_main_hub BOOLEAN NOT NULL DEFAULT FALSE, is_chapter BOOLEAN NOT NULL DEFAULT FALSE, chapter_level VARCHAR(128) NOT NULL DEFAULT 'independent_society', affiliation_status VARCHAR(128) NOT NULL DEFAULT 'draft', geographic_scope VARCHAR(128) NOT NULL DEFAULT 'custom', state VARCHAR(128) NOT NULL DEFAULT '', city VARCHAR(128) NOT NULL DEFAULT '', region VARCHAR(128) NOT NULL DEFAULT '', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS society_memberships (id INTEGER PRIMARY KEY, society_id INTEGER NOT NULL, user_id INTEGER NOT NULL, role VARCHAR(128) NOT NULL DEFAULT 'Member', status VARCHAR(64) NOT NULL DEFAULT 'active', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT uq_society_membership_role UNIQUE (society_id, user_id, role));
CREATE TABLE IF NOT EXISTS society_blueprint_audits (id INTEGER PRIMARY KEY, society_id INTEGER NOT NULL, trust_score INTEGER NOT NULL DEFAULT 1, relationships_score INTEGER NOT NULL DEFAULT 1, mutual_aid_score INTEGER NOT NULL DEFAULT 1, organization_score INTEGER NOT NULL DEFAULT 1, institutions_score INTEGER NOT NULL DEFAULT 1, businesses_score INTEGER NOT NULL DEFAULT 1, property_score INTEGER NOT NULL DEFAULT 1, community_wealth_score INTEGER NOT NULL DEFAULT 1, political_power_score INTEGER NOT NULL DEFAULT 1, weakest_area VARCHAR(128) NOT NULL DEFAULT 'Trust', strongest_area VARCHAR(128) NOT NULL DEFAULT 'Trust', recommended_next_step TEXT NOT NULL DEFAULT '', warning TEXT NOT NULL DEFAULT '', notes TEXT NOT NULL DEFAULT '', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS society_first_ten_members (id INTEGER PRIMARY KEY, society_id INTEGER NOT NULL, name VARCHAR(255) NOT NULL, email VARCHAR(255) NOT NULL DEFAULT '', phone VARCHAR(64) NOT NULL DEFAULT '', relationship_to_society VARCHAR(255) NOT NULL DEFAULT '', status VARCHAR(64) NOT NULL DEFAULT 'Considering', role VARCHAR(128) NOT NULL DEFAULT 'Member', reliability_score INTEGER NOT NULL DEFAULT 1, confidentiality_score INTEGER NOT NULL DEFAULT 1, skill_capacity_score INTEGER NOT NULL DEFAULT 1, financial_steadiness_score INTEGER NOT NULL DEFAULT 1, relationship_capacity_score INTEGER NOT NULL DEFAULT 1, possible_contribution TEXT NOT NULL DEFAULT '', notes TEXT NOT NULL DEFAULT '', invitation_status VARCHAR(64) NOT NULL DEFAULT 'not_sent', user_id INTEGER, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS society_purposes (id INTEGER PRIMARY KEY, society_id INTEGER NOT NULL, community_served TEXT NOT NULL DEFAULT '', recurring_problem TEXT NOT NULL DEFAULT '', first_focus VARCHAR(128) NOT NULL DEFAULT '', member_contribution TEXT NOT NULL DEFAULT '', day_100_goal TEXT NOT NULL DEFAULT '', not_doing_yet TEXT NOT NULL DEFAULT '', purpose_statement TEXT NOT NULL DEFAULT '', refinement_prompt TEXT NOT NULL DEFAULT '', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS society_covenants (id INTEGER PRIMARY KEY, society_id INTEGER NOT NULL, covenant_text TEXT NOT NULL DEFAULT '', version VARCHAR(64) NOT NULL DEFAULT 'v1', status VARCHAR(64) NOT NULL DEFAULT 'Draft', accepted_by_members JSON NOT NULL DEFAULT '[]', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
